"""最小化的机器人抽象层。

整体设计采用“组件组合”方式：

- 单臂机器人由一个机械臂组件组成
- 双臂机器人由两个机械臂组件组成
- 移动操作机器人由机械臂组件和移动底盘组件组成

像 PnP 这样的上层逻辑，应尽量直接依赖 `ArmComponent`，
而不是依赖某个具体机器人整机实现。
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Any, Dict, Optional

import numpy as np

from client.planner.base import Planner


@dataclass
class ArmState:
    """单个机械臂的最小运行时状态。"""

    joint_positions: np.ndarray
    eef_pose: Optional[np.ndarray] = None


@dataclass
class BaseState:
    """移动底盘的最小运行时状态。"""

    pose: Optional[np.ndarray] = None
    velocity: Optional[np.ndarray] = None


@dataclass
class RobotState:
    """组合式机器人的聚合状态。"""

    arms: Dict[str, ArmState]
    base: Optional[BaseState] = None


class RobotComponent(ABC):
    """机器人组件的共同抽象基类。

    当前先抽取各组件共有的最小接口：

    - `name`：组件名，便于调试和后续按组件绑定 planner / policy
    - `get_state()`：读取该组件当前状态
    - `stop()`：尽力停止该组件

    机械臂和底盘在控制语义上不同，因此其余动作接口仍留在各自子类中定义。
    """

    def __init__(self, name: str, planner: Optional[Planner] = None):
        self._name = name
        self._planner = planner

    @property
    def name(self) -> str:
        return self._name

    @property
    def planner(self) -> Optional[Planner]:
        """返回绑定到当前组件的 planner。

        这里返回可选值，是因为不是所有组件、也不是所有运行模式都必须启用规划。
        """

        return self._planner

    @property
    def has_planner(self) -> bool:
        """当前组件是否已经绑定 planner。"""

        return self._planner is not None

    def set_planner(self, planner: Optional[Planner]) -> None:
        """为当前组件绑定或替换 planner。"""

        self._planner = planner

    def require_planner(self) -> Planner:
        """返回当前组件绑定的 planner；若未绑定则显式报错。"""

        if self._planner is None:
            raise NotImplementedError(f"组件 '{self.name}' 当前未绑定 planner")
        return self._planner

    def shutdown_planner(self) -> None:
        """关闭当前组件绑定的 planner，并释放其外部资源。"""

        if self._planner is None:
            return
        self._planner.shutdown()
        self._planner = None

    @abstractmethod
    def get_state(self) -> Any:
        """返回当前组件状态。"""

    @abstractmethod
    def stop(self) -> None:
        """尽力停止该组件。"""


class ArmComponent(RobotComponent):
    """单个机械臂的抽象接口。

    PnP 和抓取流程应尽量直接依赖这个接口。
    """

    @abstractmethod
    def get_state(self) -> ArmState:
        """返回当前机械臂状态。"""

    @abstractmethod
    def move_pose(self, pose: np.ndarray, **kwargs: Any) -> bool:
        """控制末端执行器移动到目标位姿。"""

    @abstractmethod
    def move_joints(self, joints: np.ndarray, **kwargs: Any) -> Any:
        """执行关节空间控制或关节轨迹。"""

    @abstractmethod
    def set_gripper(self, value: float, **kwargs: Any) -> Any:
        """控制该机械臂上的夹爪。"""

    def plan_pose(
        self,
        pose_world: np.ndarray,
        *,
        max_attempts: int = 10,
    ) -> Optional[np.ndarray]:
        """使用当前绑定 planner 规划到世界系目标位姿。

        返回值语义与 planner 一致：成功时为 `(T, n_joints)` 关节轨迹，失败时返回 `None`。
        """

        return self.require_planner().plan_to_pose(
            np.asarray(pose_world, dtype=float),
            max_attempts=max_attempts,
        )


class MobileBaseComponent(RobotComponent):
    """轮式移动底盘的抽象接口。"""

    @abstractmethod
    def get_state(self) -> BaseState:
        """返回当前底盘状态。"""

    @abstractmethod
    def move(self, command: np.ndarray, **kwargs: Any) -> Any:
        """控制底盘移动。

        `command` 的具体语义由具体实现决定。
        """


class Robot:
    """机器人组件的轻量组合容器。"""

    def __init__(
        self,
        name: str,
        arms: Dict[str, ArmComponent],
        base: Optional[MobileBaseComponent] = None,
    ):
        if not arms:
            raise ValueError("Robot 至少需要一个机械臂组件")

        self._name = name
        self._arms = dict(arms)
        self._base = base

    @property
    def name(self) -> str:
        return self._name

    @property
    def arm_names(self) -> list[str]:
        return list(self._arms.keys())

    @property
    def has_base(self) -> bool:
        return self._base is not None

    def get_arm(self, arm: str) -> ArmComponent:
        if arm not in self._arms:
            raise ValueError(
                f"机器人 '{self.name}' 不包含机械臂 '{arm}'。"
                f"可用机械臂: {self.arm_names}"
            )
        return self._arms[arm]

    def get_base(self) -> MobileBaseComponent:
        if self._base is None:
            raise NotImplementedError(f"机器人 '{self.name}' 不包含移动底盘")
        return self._base

    def get_state(self) -> RobotState:
        arms = {name: arm.get_state() for name, arm in self._arms.items()}
        base = None if self._base is None else self._base.get_state()
        return RobotState(arms=arms, base=base)

    def move_arm_pose(self, arm: str, pose: np.ndarray, **kwargs: Any) -> bool:
        return self.get_arm(arm).move_pose(pose, **kwargs)

    def move_arm_joints(self, arm: str, joints: np.ndarray, **kwargs: Any) -> Any:
        return self.get_arm(arm).move_joints(joints, **kwargs)

    def set_gripper(self, arm: str, value: float, **kwargs: Any) -> Any:
        return self.get_arm(arm).set_gripper(value, **kwargs)

    def stop_arm(self, arm: str) -> None:
        self.get_arm(arm).stop()

    def move_base(self, command: np.ndarray, **kwargs: Any) -> Any:
        return self.get_base().move(command, **kwargs)

    def stop_base(self) -> None:
        self.get_base().stop()

